import{_ as a,a as t,b as i,c as d,d as o,e as n,f as l,g as s}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as r,o as c,c as p,a2 as u}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"Federated Distributed Index","description":"","frontmatter":{},"headers":[],"relativePath":"hi/Other/federated-distributed-index.md","filePath":"hi/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),h={name:"hi/Other/federated-distributed-index.md"};function b(m,e,f,g,x,q){return c(),p("div",null,[...e[0]||(e[0]=[u('<h1 id="federated-distributed-index" tabindex="-1">Federated Distributed Index <a class="header-anchor" href="#federated-distributed-index" aria-label="Permalink to &quot;Federated Distributed Index&quot;">​</a></h1><p>Federated distributed index कई ImgBed sites को एक-दूसरे के साथ file lists share करने देता है।</p><p>सरल शब्दों में:</p><ul><li>आप अपनी site के selected folders दूसरों के साथ share कर सकते हैं।</li><li>आप किसी दूसरे node से जुड़कर उसकी shared file list अपने admin panel में sync कर सकते हैं।</li><li>Federated files मुख्य रूप से browse, search और links खोलने के लिए हैं। वे आपके own storage में re-upload नहीं होतीं।</li></ul><h2 id="कहाँ-सेट-करें" tabindex="-1">कहाँ सेट करें <a class="header-anchor" href="#कहाँ-सेट-करें" aria-label="Permalink to &quot;कहाँ सेट करें&quot;">​</a></h2><p>खोलें:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+a+`" alt="Local federation node" loading="lazy"></p><p>इस page में तीन tabs हैं:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td>Local Node</td><td>अपना node enable करें, public domain confirm करें, shared folders चुनें और outbound index update करें</td></tr><tr><td>Nodes I Joined</td><td>जिन दूसरे ImgBed nodes से आप जुड़े हैं उन्हें manage करें</td></tr><tr><td>Nodes Joining Me</td><td>जो लोग आपके node से जुड़ना चाहते हैं उनकी requests manage करें</td></tr></tbody></table><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li><code>Local Node</code> खोलें।</li><li><code>Enable</code> on करें।</li><li><code>Sync folders</code> में share करने वाले folders select करें।</li><li><code>Update Outbound Index</code> पर click करें।</li><li>अगर ImgBed domain change detect करे, तो आगे बढ़ने से पहले confirm करें कि current domain सही है।</li></ol><p>आप multiple sync folders select कर सकते हैं।</p><p>अगर sync folder list empty है, तो सभी folders share होंगे।</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>Public domain वह site URL है जिससे दूसरे nodes आपके node को access करते हैं।</p><p>ImgBed इसे automatically detect करता है। आपको manually type करने की ज़रूरत नहीं। पहली बार index update करते समय ImgBed पूछता है कि current access URL production domain है या नहीं।</p><p>अगर बाद में domain बदलते हैं, तो index update करने पर confirmation फिर से माँगा जाएगा।</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders तय करते हैं कि federation nodes के साथ कौन सी files share होंगी।</p><p>उदाहरण के लिए, अगर आप केवल यह select करते हैं:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>तो दूसरे nodes सिर्फ इन दो directories की files देख पाएँगे।</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>यह उस file list को update करता है जिसे दूसरे nodes आपसे sync कर सकते हैं।</p><p>इसे तब इस्तेमाल करें जब:</p><ul><li>आप पहली बार federation enable कर रहे हों।</li><li>आपने ऐसी files upload की हैं जिन्हें share करना है।</li><li>आपने sync folders बदले हैं।</li><li>आपने public domain बदला है और उसे confirm करना है।</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> वह जगह है जहाँ आप दूसरे nodes subscribe करते हैं।</p><p><img src="`+t+'" alt="Nodes I joined" loading="lazy"></p><h3 id="दूसरे-node-में-join-request-भेजना" tabindex="-1">दूसरे Node में Join Request भेजना <a class="header-anchor" href="#दूसरे-node-में-join-request-भेजना" aria-label="Permalink to &quot;दूसरे Node में Join Request भेजना&quot;">​</a></h3><ol><li>दूसरे owner से invitation link माँगें।</li><li>उसे input box में paste करें।</li><li><code>Request to Join</code> पर click करें।</li><li>दूसरे owner द्वारा admin panel में approve करने का इंतज़ार करें।</li></ol><p>Approval के बाद node status approved हो जाता है।</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> आपके joined nodes से file lists sync करता है।</p><p>इसे तब इस्तेमाल करें जब:</p><ul><li>दूसरे owner ने अभी आपकी request approve की है।</li><li>दूसरे owner ने बताया है कि shared content update हुआ है।</li><li>आप सभी joined federation file lists refresh करना चाहते हैं।</li></ul><p>सिर्फ एक node update करने के लिए उस node card पर <code>Update Index</code> click करें।</p><p><img src="'+i+'" alt="Update index" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>अगर अब किसी node को sync नहीं करना चाहते, तो <code>Unsubscribe</code> click करें।</p><p>Unsubscribe करने के बाद उस node का federated index आपकी local site से हट जाता है।</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> वह जगह है जहाँ आप दूसरों की requests handle करते हैं।</p><p><img src="'+d+'" alt="Nodes joining me" loading="lazy"></p><h3 id="invitation-link-generate-करना" tabindex="-1">Invitation Link Generate करना <a class="header-anchor" href="#invitation-link-generate-करना" aria-label="Permalink to &quot;Invitation Link Generate करना&quot;">​</a></h3><ol><li>Confirm करें कि local node enabled है।</li><li><code>Update Outbound Index</code> कम से कम एक बार click करें, ताकि ImgBed public domain confirm कर सके।</li><li><code>Nodes Joining Me</code> खोलें।</li><li><code>Reset Invitation Link</code> click करें।</li><li>Invitation link copy करें और दूसरे owner को भेजें।</li></ol><p>अगर invitation link empty है, तो आम तौर पर public domain अभी confirm नहीं हुआ है। <code>Local Node</code> पर वापस जाएँ और <code>Update Outbound Index</code> click करें।</p><h3 id="join-requests-handle-करना" tabindex="-1">Join Requests Handle करना <a class="header-anchor" href="#join-requests-handle-करना" aria-label="Permalink to &quot;Join Requests Handle करना&quot;">​</a></h3><p>जब कोई request submit करता है, तो वह <code>Nodes Joining Me</code> list में दिखती है।</p><table tabindex="0"><thead><tr><th>Action</th><th>Meaning</th></tr></thead><tbody><tr><td>Approve</td><td>दूसरे node को आपकी shared file list sync करने देता है</td></tr><tr><td>Reject</td><td>Join request मना करता है</td></tr><tr><td>Delete</td><td>Finished record हटाता है</td></tr><tr><td>Check Status</td><td>Check करता है कि दूसरी side अभी भी यह relationship रखती है या नहीं</td></tr></tbody></table><p>Approval के बाद भी दूसरी side को <code>Update Inbound Index</code> click करना होगा, तभी आपकी shared files वहाँ दिखेंगी।</p><p><img src="'+o+'" alt="Approve invited node" loading="lazy"></p><h2 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h2><p>Relationship approve होने के बाद node card पर <code>Message</code> click करें।</p><p>Messages सिर्फ federation relationship के बारे में communication के लिए हैं। ये files, tags, directories या permissions नहीं बदलते।</p><p><img src="'+n+'" alt="Messages" loading="lazy"></p><h2 id="federated-files-देखना" tabindex="-1">Federated Files देखना <a class="header-anchor" href="#federated-files-देखना" aria-label="Permalink to &quot;Federated Files देखना&quot;">​</a></h2><p>Sync complete होने के बाद admin file list पर लौटें।</p><p>Page के ऊपर local files और federated files के बीच switch करें। Federated files में synced content browse कर सकते हैं।</p><p>Federated files मुख्य रूप से viewing, searching, previewing और links copy करने के लिए हैं। ये local files नहीं हैं, इसलिए आप इन्हें अपनी site से move, delete, retag या backup नहीं कर सकते।</p><p><img src="'+l+'" alt="Federated files in admin" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="no-relationship-record-की-वजह-से-reapply-क्यों-कह-रहा-है" tabindex="-1">&quot;No Relationship Record&quot; की वजह से Reapply क्यों कह रहा है? <a class="header-anchor" href="#no-relationship-record-की-वजह-से-reapply-क्यों-कह-रहा-है" aria-label="Permalink to &quot;&quot;No Relationship Record&quot; की वजह से Reapply क्यों कह रहा है?&quot;">​</a></h3><p>आम तौर पर इसका मतलब है कि दूसरी side ने आपको delete करके record हटा दिया है, इसलिए relationship अब नहीं मिल रहा। नई join request submit करें।</p><p><img src="'+s+'" alt="Reapply when no relationship record exists" loading="lazy"></p><h3 id="join-करने-के-बाद-files-क्यों-नहीं-दिख-रहीं" tabindex="-1">Join करने के बाद Files क्यों नहीं दिख रहीं? <a class="header-anchor" href="#join-करने-के-बाद-files-क्यों-नहीं-दिख-रहीं" aria-label="Permalink to &quot;Join करने के बाद Files क्यों नहीं दिख रहीं?&quot;">​</a></h3><p>Check करें:</p><ol><li>दूसरे owner ने आपकी request approve की है।</li><li>दूसरे owner ने <code>Update Outbound Index</code> click किया है।</li><li>आपने <code>Update Inbound Index</code> click किया है।</li><li>दूसरे owner के sync folders में वे directories शामिल हैं जिन्हें वे share करना चाहते हैं।</li></ol><h3 id="domain-change-detect-होने-पर-क्या-करें" tabindex="-1">Domain Change Detect होने पर क्या करें? <a class="header-anchor" href="#domain-change-detect-होने-पर-क्या-करें" aria-label="Permalink to &quot;Domain Change Detect होने पर क्या करें?&quot;">​</a></h3><p>अगर आप अभी admin panel production domain से खोल रहे हैं, तो confirm करके continue करें।</p><p>अगर आप temporary address इस्तेमाल कर रहे हैं, तो cancel करें, production domain से admin panel दोबारा खोलें, फिर कोशिश करें।</p><h3 id="empty-sync-folder-list-का-क्या-मतलब-है" tabindex="-1">Empty Sync Folder List का क्या मतलब है? <a class="header-anchor" href="#empty-sync-folder-list-का-क्या-मतलब-है" aria-label="Permalink to &quot;Empty Sync Folder List का क्या मतलब है?&quot;">​</a></h3><p>Empty sync folder list का मतलब है कि सभी folders share होंगे।</p><p>केवल कुछ directories share करनी हों, तो वे folders manually select करें।</p><h3 id="outbound-और-inbound-index-updates-में-फर्क" tabindex="-1">Outbound और Inbound Index Updates में फर्क <a class="header-anchor" href="#outbound-और-inbound-index-updates-में-फर्क" aria-label="Permalink to &quot;Outbound और Inbound Index Updates में फर्क&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>Simple Meaning</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>जो content दूसरे मुझसे sync कर सकते हैं उसे update करता है</td></tr><tr><td>Update Inbound Index</td><td>जो content मैंने दूसरों से sync किया है उसे update करता है</td></tr></tbody></table>',78)])])}const _=r(h,[["render",b]]);export{I as __pageData,_ as default};
